  ('pukao-d0d1b9a2-moex-00224', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司生產一種零件，可用於製造該公司所生產的其中一種產品，生產該項零件12,000單位所發 生的成本包括：直接材料成本$92,000、直接人工成本$140,000、變動製造費用$68,000、固定製造 費用$156,000。乙公司願意以每個零件$36 供應甲公司12,000單位的相同零件。若甲公司向乙公 司購買零件，固定製造費用中有$60,000是可免成本（avoidablecost），但生產該零件的生產設備 並沒有任何其他用途，甲公司應該採取下列何項決策？', '["自己生產該零件，因為與向乙公司購買零件相比，平均每單位可以節省$6", "向乙公司購買該零件，因為與自己生產零件相比，平均每單位可以節省$2", "向乙公司購買該零件，因為與自己生產零件相比，可以為公司節省$30,000的成本", "自己生產該零件，因為與向乙公司購買零件相比，平均每單位可以節省$2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00225', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '下列何者最能說明為何淨現值法優於內部報酬率法？', '["淨現值法考慮貨幣的時間價值", "淨現值法以初始投資百分比的方式表達", "相較於內部報酬率法，在淨現值法下計算的報酬率很容易比較", "個別方案的淨現值可以加總，以決定接受不同方案組合的影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00226', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司計畫購買新的倉儲設備，以提升公司控制庫存的能力，該設備的售價為$36,586，需要$4,000 的營運資金，估計使用年限為5年，殘值為$4,000，在到達使用期限時，營運資金$4,000可以回 收，購買該設備每年可節省現金$10,000。該投資的回收期間為何？', '["3.01年", "3.26年", "3.66年", "4.06年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00227', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司與乙公司皆產銷電腦鍵盤，甲公司單位產品成本$20，變動成本占40%。乙公司單位產品成 本$10，變動成本占60%，二公司產品訂價皆採成本加成訂價法。甲公司採全部成本（full cost） 而非變動成本（variablecost）加成訂價，最可能的原因是下列何者？', '["甲公司之產能利用率較乙公司低", "甲公司單位產品成本較乙公司高", "甲公司的變動成本比重較乙公司高", "甲公司業務員競價能力較乙公司高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00228', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '當轉出部門的產品無外在市場時，有關成本基礎轉撥計價法之敘述，下列何者正確？', '["從公司整體的角度應將轉出部門視為成本中心", "從公司整體的角度應將轉出部門視為利潤中心", "以實際成本為移轉價格將使轉出部門生產之效率隨成本之移轉而轉嫁予轉入部門", "以標準成本為移轉價格將使轉出部門生產之效率隨成本之移轉而轉嫁予轉入部門"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00229', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '若轉出部門有閒置產能，其每單位產品的變動成本與全部成本分別為$50與$80，則內部移轉該產 品的機會成本為何？', '["$0", "$30", "$50", "$80"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "e4cd6100a25c", "answer_pdf_sha1": "65c335a2499f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
